  	//-------------------------------------------------------------------------
  	// 조회
	//-------------------------------------------------------------------------
	scwin.f_Retrieve = async function () {
	  	//validation check   
	  	if(acb_qryConKnd.getValue()== "오더일자"){  
    		if(!await $c.gus.cfValidate([ed_regBranCd,ica_qryConDtFm,ica_qryConDtTo])){
    			return;
    		}
		  	//조회시작일자가 더 클경우 체크
		  	if (!await $c.gus.cfIsAfterDate(ica_qryConDtFm.getValue(), ica_qryConDtTo.getValue())) {
	 	       await $c.gus.cfAlertMsg(MSG_CM_ERR_039);
	 	       return;
	    	}
    	}else{
    		if(!await $c.gus.cfValidate([ed_regBranCd,ed_qryConCd])){
    			return;
    		}
    	}


/*
     	var dsHeader = "regBranCd:STRING,qryConKnd:STRING,qryConDtFm:STRING,qryConDtTo:STRING,qryConCd:STRING,"+
